func loadLocalTransactions(ctx context.Context, db *store.Store) ([]localTransaction, error) {
	seen := map[string]bool{}
	var out []localTransaction
	rows, err := db.DB().QueryContext(ctx, `SELECT data FROM transactions`)
	if err != nil && !errors.Is(err, sql.ErrNoRows) {
		return nil, err
	}
	if err == nil {
		defer rows.Close()
		for rows.Next() {
			var raw string
			if err := rows.Scan(&raw); err != nil {
				return nil, err
			}
			tx, ok := decodeLocalTransaction([]byte(raw))
			if ok {
				out = append(out, tx)
				seen[tx.ID] = true
			}
		}
		if err := rows.Err(); err != nil {
			return nil, err
		}
	}

	objs, err := loadResourceObjects(ctx, db, "transactions")
	if err != nil {
		return nil, err
	}
	for _, obj := range objs {
		raw, _ := json.Marshal(obj)
		tx, ok := decodeLocalTransaction(raw)
		if ok && !seen[tx.ID] {
			out = append(out, tx)
		}
	}
	return out, nil
}

func decodeLocalTransaction(raw []byte) (localTransaction, bool) {
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return localTransaction{}, false
	}
	id := localID(obj, "id")
	dateString := localString(obj, "date")
	date, _ := parseLocalDate(dateString)
	payee := localString(obj, "payee")
	if id == "" || payee == "" {
		return localTransaction{}, false
	}
	return localTransaction{
		ID:              id,
		Payee:           payee,
		PayeeNormalized: normalizeLocalPayee(payee),
		Amount:          localFloat(obj, "amount"),
		Date:            date,
		DateString:      dateString,
		CategoryID:      localID(obj, "category_id", "categoryId"),
		RecurringID:     localID(obj, "recurring_id", "recurringId"),
		Status:          localString(obj, "status"),
		GroupParentID:   localID(obj, "group_parent_id", "group_id", "groupParentId"),
		SplitParentID:   localID(obj, "split_parent_id", "parent_id", "splitParentId"),
		IsGroupParent:   localBool(obj, "is_group_parent", "isGroupParent"),
		IsSplitParent:   localBool(obj, "is_split_parent", "isSplitParent"),
	}, true
}

func loadResourceObjects(ctx context.Context, db *store.Store, resourceTypes ...string) ([]map[string]any, error) {
	var out []map[string]any
	for _, resourceType := range resourceTypes {
		rows, err := db.DB().QueryContext(ctx, `SELECT data FROM resources WHERE resource_type = ? ORDER BY updated_at DESC`, resourceType)
		if err != nil {
			return nil, err
		}
		for rows.Next() {
			var raw string
			if err := rows.Scan(&raw); err != nil {
				rows.Close()
				return nil, err
			}
			out = append(out, expandResourceObjects(resourceType, []byte(raw))...)
		}
		if err := rows.Err(); err != nil {
			rows.Close()
			return nil, err
		}
		if err := rows.Close(); err != nil {
			return nil, err
		}
	}
	return out, nil
}

func expandResourceObjects(resourceType string, raw []byte) []map[string]any {
	trimmed := strings.TrimSpace(string(raw))
	if trimmed == "" || trimmed == "null" || trimmed == "[]" || trimmed == "{}" {
		return nil
	}
	var arr []map[string]any
	if err := json.Unmarshal(raw, &arr); err == nil {
		return arr
	}
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return nil
	}
	if _, ok := obj["dry_run"]; ok && len(obj) == 1 {
		return nil
	}
	for _, key := range resourceArrayKeys(resourceType) {
		if v, ok := obj[key]; ok {
			if rows := anySliceToMaps(v); len(rows) > 0 {
				return rows
			}
		}
	}
	return []map[string]any{obj}
}

func resourceArrayKeys(resourceType string) []string {
	resourceKey := strings.ReplaceAll(resourceType, "-", "_")
	keys := []string{resourceKey, "data", "results", "items", "records"}
	switch resourceType {
	case "manual-accounts":
		keys = append([]string{"manual_accounts"}, keys...)
	case "plaid-accounts":
		keys = append([]string{"plaid_accounts"}, keys...)
	case "recurring-items":
		keys = append([]string{"recurring_items"}, keys...)
	case "balance-history":
		keys = append([]string{"balance_history"}, keys...)
	case "crypto":
		keys = append([]string{"crypto_manual"}, keys...)
	case "crypto-synced":
		keys = append([]string{"crypto_synced"}, keys...)
	}
	return keys
}

func anySliceToMaps(v any) []map[string]any {
	items, ok := v.([]any)
	if !ok {
		return nil
	}
	out := make([]map[string]any, 0, len(items))
	for _, item := range items {
		if obj, ok := item.(map[string]any); ok {
			out = append(out, obj)
		}
	}
	return out
}

func anyMap(v any) map[string]any {
	if obj, ok := v.(map[string]any); ok {
		return obj
	}
	return nil
}

func balanceHistorySourceKey(obj map[string]any) (string, string) {
	src := anyMap(obj["source"])
	if src == nil {
		src = obj
	}
	accountType := localString(src, "type")
	switch accountType {
	case "manual":
		return accountType, localID(src, "manual_account_id")
	case "plaid":
		return accountType, localID(src, "plaid_account_id")
	case "crypto_manual":
		return accountType, localID(src, "crypto_manual_id")
	case "crypto_synced":
		return accountType, localID(src, "crypto_synced_id")
	default:
		return accountType, ""
	}
}

func latestHistoryDate(obj map[string]any) string {
	best := time.Time{}
	bestString := ""
	for _, row := range anySliceToMaps(obj["balances"]) {
		dateString := localString(row, "date")
		date, err := parseLocalDate(dateString)
		if err == nil && date.After(best) {
			best = date
			bestString = dateString
		}
	}
	if bestString == "" {
		bestString = localString(obj, "date")
	}
	return bestString
}

func loadCategoryNames(ctx context.Context, db *store.Store) (map[string]string, error) {
	objs, err := loadResourceObjects(ctx, db, "categories")
	if err != nil {
		return nil, err
	}
	names := map[string]string{}
	var walk func(map[string]any)
	walk = func(obj map[string]any) {
		if id, name := localID(obj, "id"), localString(obj, "name"); id != "" && name != "" {
			names[id] = name
		}
		for _, child := range anySliceToMaps(obj["children"]) {
			walk(child)
		}
	}
	for _, obj := range objs {
		walk(obj)
	}
	return names, nil
}

